import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { afterEach, beforeEach, describe, expect, it } from 'vitest';
import { loadEnv } from '../env';

const ENV_VAR = 'CHROME_EXTENSION_ID';

describe('loadEnv', () => {
  let cwd: string;
  let projectDir: string;
  let originalValue: string | undefined;

  beforeEach(() => {
    cwd = process.cwd();
    originalValue = process.env[ENV_VAR];
    delete process.env[ENV_VAR];
    projectDir = mkdtempSync(join(tmpdir(), 'wxt-env-test-'));
    process.chdir(projectDir);
  });

  afterEach(() => {
    process.chdir(cwd);
    rmSync(projectDir, { recursive: true, force: true });
    if (originalValue == null) {
      delete process.env[ENV_VAR];
    } else {
      process.env[ENV_VAR] = originalValue;
    }
  });

  it('loads .env variables into process.env', () => {
    writeFileSync('.env', `${ENV_VAR}=chrome-id\n`);

    loadEnv('production', 'chrome');

    expect(process.env[ENV_VAR]).toBe('chrome-id');
  });
});

